  "question": "368. What is the favorable place for AV fistula?",
  "options": {
    "A": "brachial artery basilic vein",
    "B": "brachial artery cephalic vein",
    "C": "radial artery basilic vein",
    "D": "radial artery cephalic vein"
  },
